promptInstructions:
You are a migration planning assistant. Analyze the provided code and create a detailed migration plan.

**Migration type**: {{.stateKeys.migrationType}}
{{.migrationTypeInstructions}}

**Risk tolerance**: {{.stateKeys.riskTolerance}}
{{.riskToleranceInstructions}}

{{if index .stateKeys "targetVersion"}}**Target version**: {{index .stateKeys "targetVersion"}}
{{end}}
For each file or component that needs migration:
1. Identify all breaking changes and deprecations
2. Map old patterns to new patterns with before/after examples
3. Flag any data loss risks or behavioral changes
4. Estimate effort and identify dependencies between migration steps
5. Suggest an ordering that minimizes risk of partial migration states

commands.handler:
function (args) {
  var valid = ['api', 'database', 'framework', 'language'];
  if (!args || args.length === 0) {
    output.print('Current migration type: ' + state.get(stateKeys.migrationType));
    output.print('Available: ' + valid.join(', '));
    return;
  }
  var t = args[0].toLowerCase();
  if (valid.indexOf(t) === -1) {
    output.print('Unknown type: ' + t + '. Available: ' + valid.join(', '));
    return;
  }
  state.set(stateKeys.migrationType, t);
  output.print('Migration type set to: ' + t);
}

function (args) {
  var valid = ['conservative', 'moderate', 'aggressive'];
  if (!args || args.length === 0) {
    output.print('Current risk tolerance: ' + state.get(stateKeys.riskTolerance));
    output.print('Available: ' + valid.join(', '));
    return;
  }
  var r = args[0].toLowerCase();
  if (valid.indexOf(r) === -1) {
    output.print('Unknown risk level: ' + r + '. Available: ' + valid.join(', '));
    return;
  }
  state.set(stateKeys.riskTolerance, r);
  output.print('Risk tolerance set to: ' + r);
}

function (args) {
  if (!args || args.length === 0) {
    var current = state.get(stateKeys.targetVersion);
    output.print('Current target version: ' + (current || '(not set)'));
    return;
  }
  var version = args.join(' ');
  state.set(stateKeys.targetVersion, version);
  output.print('Target version set to: ' + version);
}

function (args) {
  var mtype = state.get(stateKeys.migrationType);
  var risk = state.get(stateKeys.riskTolerance);
  var target = state.get(stateKeys.targetVersion);
  output.print('Pre-Migration Checklist');
  output.print('=======================');
  output.print('');
  output.print('Configuration:');
  output.print('  Migration type:   ' + mtype);
  output.print('  Risk tolerance:   ' + risk);
  output.print('  Target version:   ' + (target || '(not set)'));
  output.print('');
  output.print('Checklist:');
  output.print('  [ ] Source files added to context');
  output.print('  [ ] Target version specified');
  output.print('  [ ] Migration type confirmed');
  if (risk === 'conservative') {
    output.print('  [ ] Rollback procedures documented');
    output.print('  [ ] Feature flags prepared');
  }
  if (mtype === 'database') {
    output.print('  [ ] Database backup verified');
    output.print('  [ ] Migration script tested on staging');
  }
  output.print('');
  output.print('Ready? Use "copy" to generate the migration plan.');
}
